always @(posedge clk) begin
  ready = 1'b0;
  #10;
  ready = 1'b1;
end

forever begin
  ready = 1'b0;
  for (int i = 0; i < 10; ++i)
    @(posedge clk);
  ready = 1'b1;
  @(posedge clk);
  #1;
end

logic ready;
always @(posedge clk) begin
  @(posedge clk);
  #1;
  ready = 1'b1;
end
